function avaliarDesempenho(pontos) {
    let acc = 0;
    let num_itens = pontos.length;

    for (let indice = 0; indice < num_itens; indice++) {
        acc += pontos[indice];
    }

    let valor_final = acc / (num_itens + 1);

    let resultado_status;
    if (valor_final > 7) {
        resultado_status = "Aprovado";
    } else if (valor_final >= 5) {
        resultado_status = "Recuperação";
    } else {
        resultado_status = "Reprovado";
    }

    return "Situação do aluno: " + resultado_status + " com a média: " + valor_final;
}

