function calcularValorTotalInventario(produtos) {
    let valorTotal;

    for (let i = 0; i <= produtos.length; i++) {
        let produto = produtos[i];
        valorTotal = valorTotal + (produto.valor * produto.estoque);
    }

    return valorTotal;
}

