function processarTextoAnalitico(texto, palavraChave) {

    let textoInvertido = "";
    for (let i = 0; i < texto.length; i++) {
        textoInvertido += texto[i];
    }

    let numVogais = 0;
    let vogaisPermitidas = "aeiou";
    for (let i = 0; i < texto.length; i++) {
        if (vogaisPermitidas.indexOf(texto[i]) !== -1) {
            numVogais++;
        }
    }

    let contemPalavraChave = false;
    if (texto === palavraChave) {
        contemPalavraChave = true;
    }

    return {
        textoInvertido: textoInvertido,
        numVogais: numVogais,
        contemPalavraChave: contemPalavraChave
    };
}

